const input = $json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function cleanAction(value) {
  return clean(value).toLowerCase();
}

function cleanLimit(value) {
  const parsed = parseInt(value, 10);
  if (!Number.isFinite(parsed)) return "5";
  return String(Math.max(1, Math.min(parsed, 10)));
}

function firstRegex(text, regex) {
  const match = text.match(regex);
  return match ? clean(match[1] || match[0]) : "";
}

function inferCustomerName(text, orderId, phone, conversationId) {
  if (!text || orderId || phone || conversationId) return "";

  let candidate = firstRegex(text, /(?:for|customer|name)\s+(.+)/i) || text;
  candidate = candidate
    .replace(/\b(find|search|show|open|get|look\s*up|lookup|order|orders|summary|status|document|documents|quote|invoice|please|pls|me|the|for|customer|name|send|latest|to)\b/gi, " ")
    .replace(/[^a-zA-Z\s'-]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  if (candidate.length < 2 || candidate.length > 80) return "";
  return candidate;
}

const allowedActions = new Set([
  "find_order",
  "get_order_summary",
  "get_order_documents",
  "prepare_latest_quote_send",
]);

const rawInput = clean(input.input || input.message_text || input.query || input.text || input.message);
const rawAction = cleanAction(input.action);
const inferredOrderId = firstRegex(rawInput, /\b(ORD-\d{4}-[A-Z0-9]{4,})\b/i).toUpperCase();
const inferredConversationId = firstRegex(rawInput, /\bconversation(?:\s*id)?\s*[:#]?\s*(\d+)\b/i);
const phoneCandidate = firstRegex(rawInput, /(?:\+?\d[\d\s().-]{6,}\d)/);
const inferredPhone = phoneCandidate.replace(/[^\d+]/g, "");

const orderId = (clean(input.order_id) || inferredOrderId).toUpperCase();
const customerPhone = clean(input.customer_phone) || inferredPhone;
const conversationId = clean(input.conversation_id) || inferredConversationId;
const customerName = clean(input.customer_name) || inferCustomerName(rawInput, orderId, customerPhone, conversationId);
const telegramChatId = clean(input.telegram_chat_id || input.user_id);
const telegramUserId = clean(input.telegram_user_id || input.user_id);
const telegramUserName = clean(input.telegram_user_name || input.user_name);

const requestedStatusScope = clean(input.status_scope).toLowerCase();
const statusScope = ["active", "history", "all"].includes(requestedStatusScope) ? requestedStatusScope : "active";
const limit = cleanLimit(input.limit || 5);
const changedBy = clean(input.changed_by) || telegramUserName || "Oom Sakkie";

let action = rawAction;
if (!allowedActions.has(action)) {
  if (/\b(send|stuur)\b/i.test(rawInput) && /\b(quote|kwotasie)\b/i.test(rawInput) && orderId) {
    action = "prepare_latest_quote_send";
  } else if (/\b(document|documents|quote|invoice|pdf)\b/i.test(rawInput) && orderId) {
    action = "get_order_documents";
  } else if (orderId) {
    action = "get_order_summary";
  } else {
    action = "find_order";
  }
}

let validationError = "";
if (action === "find_order" && !orderId && !customerPhone && !customerName && !conversationId) {
  action = "invalid_lookup_action";
  validationError = "Provide order_id, customer_phone, customer_name, or conversation_id for find_order.";
}

if ((action === "get_order_summary" || action === "get_order_documents" || action === "prepare_latest_quote_send") && !orderId) {
  action = "invalid_lookup_action";
  validationError = "Provide order_id for order summary, document lookup, or quote-send preparation.";
}

if (action === "prepare_latest_quote_send" && !telegramChatId) {
  action = "invalid_lookup_action";
  validationError = "Telegram chat context is required to prepare quote send buttons.";
}

const searchParams = [];
if (orderId) searchParams.push(["order_id", orderId]);
if (customerPhone) searchParams.push(["customer_phone", customerPhone]);
if (customerName) searchParams.push(["customer_name", customerName]);
if (conversationId) searchParams.push(["conversation_id", conversationId]);
if (statusScope) searchParams.push(["status_scope", statusScope]);
if (limit) searchParams.push(["limit", limit]);

const query = searchParams
  .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
  .join("&");

return [
  {
    json: {
      action,
      input: rawInput,
      order_id: orderId,
      customer_phone: customerPhone,
      customer_name: customerName,
      conversation_id: conversationId,
      telegram_chat_id: telegramChatId,
      telegram_user_id: telegramUserId,
      telegram_user_name: telegramUserName,
      status_scope: statusScope,
      limit,
      changed_by: changedBy,
      validation_error: validationError,
      search_url: `https://amadeus-pig-tracking-system.onrender.com/api/orders/search?${query}`,
      operator_summary_url: orderId
        ? `https://amadeus-pig-tracking-system.onrender.com/api/orders/${encodeURIComponent(orderId)}/operator-summary`
        : "",
      prepare_quote_send_url: orderId
        ? `https://amadeus-pig-tracking-system.onrender.com/api/orders/${encodeURIComponent(orderId)}/quote/prepare-send`
        : "",
      prepare_quote_send_body: {
        conversation_id: conversationId,
        requested_by: changedBy,
      },
    },
  },
];

const item = $json || {};
const matches = Array.isArray(item.matches) ? item.matches : [];

function lineForMatch(match) {
  const bits = [
    match.order_id,
    match.customer_name,
    match.order_status,
    match.payment_status,
  ].filter(Boolean);
  return `- ${bits.join(" | ")}`;
}

let message = item.message || "Order search completed.";
if (item.lookup_status === "multiple_matches" && matches.length) {
  message += "\n" + matches.map(lineForMatch).join("\n");
  message += "\nPlease choose one order ID.";
} else if (item.lookup_status === "single_match" && matches[0]) {
  message += `\n${lineForMatch(matches[0])}`;
}

return [
  {
    json: {
      success: item.success === true,
      action: "find_order",
      lookup_status: item.lookup_status || "error",
      match_count: item.match_count || 0,
      status_scope: item.status_scope || "",
      message,
      matches,
    },
  },
];

const item = $json || {};
const order = item.order_summary || {};
const lines = Array.isArray(item.line_summary) ? item.line_summary : [];
const docs = Array.isArray(item.document_summary) ? item.document_summary : [];
const actions = Array.isArray(item.outstanding_actions) ? item.outstanding_actions : [];

const lineText = lines.map((line) => {
  return `${line.quantity || 0} x ${line.sex || ""} ${line.sale_category || ""} ${line.weight_band || ""} @ R${line.unit_price || 0}`.replace(/\s+/g, " ").trim();
}).join("; ");

const docText = docs.map((doc) => `${doc.document_type || "Document"} ${doc.document_ref || ""} (${doc.document_status || ""})`).join("; ");
const actionText = actions.map((action) => action.label || action.code).filter(Boolean).join("; ");

const message = [
  `Order ${order.order_id || item.order_id || ""}: ${order.order_status || ""} / ${order.approval_status || ""}`,
  order.customer_name ? `Customer: ${order.customer_name}` : "",
  lineText ? `Items: ${lineText}` : "Items: none active",
  `Total: R${order.active_line_total || 0}`,
  order.payment_method ? `Payment: ${order.payment_method} (${order.payment_status || ""})` : "",
  order.collection_location ? `Collection: ${order.collection_location}${order.collection_date ? ", " + order.collection_date : ""}` : "",
  docText ? `Documents: ${docText}` : "Documents: none",
  actionText ? `Outstanding: ${actionText}` : "",
].filter(Boolean).join("\n");

return [
  {
    json: {
      success: item.success === true,
      action: "get_order_summary",
      lookup_status: item.lookup_status || "error",
      order_id: item.order_id || order.order_id || "",
      message,
      order_summary: order,
      line_summary: lines,
      document_summary: docs,
      outstanding_actions: actions,
      safe_document_actions: Array.isArray(item.safe_document_actions) ? item.safe_document_actions : [],
    },
  },
];

const item = $json || {};
const docs = Array.isArray(item.document_summary) ? item.document_summary : [];
const orderId = item.order_id || (item.order_summary || {}).order_id || "";

const lines = docs.map((doc) => {
  const parts = [
    doc.document_type || "Document",
    doc.document_ref || doc.document_id || "",
    doc.document_status || "",
    doc.total !== undefined ? `R${doc.total}` : "",
  ].filter(Boolean);
  return `- ${parts.join(" | ")}`;
});

const message = lines.length
  ? `Documents for ${orderId}:\n${lines.join("\n")}`
  : `No documents found for ${orderId}.`;

return [
  {
    json: {
      success: item.success === true,
      action: "get_order_documents",
      lookup_status: item.lookup_status || "error",
      order_id: orderId,
      message,
      document_summary: docs,
      safe_document_actions: Array.isArray(item.safe_document_actions) ? item.safe_document_actions : [],
    },
  },
];

const item = $json || {};
const doc = item.document || {};
const dest = item.destination || {};
const buttons = item.button_context || {};

if (item.success !== true || item.send_ready !== true) {
  const errors = Array.isArray(item.errors) ? item.errors.join("; ") : "Quote send preparation failed.";
  return [{
    json: {
      success: false,
      action: "prepare_latest_quote_send",
      lookup_status: "error",
      message: errors,
    },
  }];
}

const total = doc.total !== undefined && doc.total !== "" ? `R${doc.total}` : "total not set";
const text = [
  item.message || `Quote ${doc.document_ref || ""} is ready to send.`,
  "",
  `Order: ${item.order_id || ""}`,
  `Document: ${doc.document_ref || doc.document_id || ""}`,
  `Customer: ${item.customer_name || ""}`,
  `Destination conversation: ${dest.conversation_id || ""}`,
  `Total: ${total}`,
].filter((line) => line !== undefined && line !== null).join("\n");

return [{
  json: {
    success: true,
    action: "prepare_latest_quote_send",
    lookup_status: "send_prepared",
    order_id: item.order_id || "",
    message: "Quote send confirmation buttons prepared.",
    telegram_chat_id: item.telegram_chat_id || "",
    telegram_message: text,
    document: doc,
    destination: dest,
    button_context: buttons,
  },
}];

return [{
  json: {
    success: true,
    action: "prepare_latest_quote_send",
    lookup_status: "send_prepared",
    message: "I prepared the quote send confirmation buttons. Use the Telegram buttons to send or cancel.",
  },
}];

